def f25(s, a):
    mag = math.sqrt(a[0]**2 + a[1]**2)
    if mag < 1e-6:
        return False
    return abs(a[0]) / mag > 0.9

def f26(s, a):
    mag = math.sqrt(a[0]**2 + a[1]**2)
    if mag < 1e-6:
        return False
    return abs(a[1]) / mag > 0.9

def f27(s, a):
    mag = math.sqrt(a[0]**2 + a[1]**2)
    if mag < 1e-6:
        return False
    cos45 = abs(a[0] / mag) - 1/math.sqrt(2)
    return abs(cos45) < 0.3

def f92(s, a):
    count = 0
    for i in range(5):
        if abs(a[i]) > 1e-3:
            count += 1
    return count > 1
